import { MouseEvent as ReactMouseEvent } from 'react';

import { useTooltip } from '../../core/components/overlay-tooltip/contexts/TooltipContext.js';
import type { Data } from '../../core/components/overlay-tooltip/types.js';
import { useTooltipActions } from '../../core/components/overlay-tooltip/useTooltipActions.js';
import { useEventErrorHandler } from '../../core/hooks/useEventErrorHandler.js';
import type { Formatter } from '../../core/types/formatter.js';
import type { InternalSliceData } from '../types/internal/pie-chart.js';
import { getTooltipContent } from '../utils/get-tooltip-content.js';

const buildTooltipData = (
  sliceId: string,
  data: InternalSliceData,
  handlerCatch: (callback: unknown) => number,
  formatter: Formatter,
): Data => {
  const tooltipContent = getTooltipContent(
    sliceId,
    data,
    handlerCatch,
    formatter,
  );

  return {
    metadata: {
      sliceId: data.id,
    },
    geometry: 'pie',
    series: [
      {
        name: tooltipContent.name,
        value: tooltipContent.absoluteValue,
        color: tooltipContent.color,
        relativeValue: tooltipContent.relativeValue,
        relativeValueUnit: '%',
      },
    ],
  };
};

/**
 * Hook that generates handlers for mouse interactions.
 * @param sliceId - Id of the slice.
 * @param data - Slice data for this slice.
 * @param formatter - Formatter to be used.
 * @returns Handlers to perform mouse interactions.
 */
export function useSliceHandlers(
  sliceId: string,
  data: InternalSliceData,
  formatter: Formatter,
) {
  const handlerCatch = useEventErrorHandler();
  const tooltipState = useTooltip();
  const { hover, pin, unpin, reset } = useTooltipActions();

  const onPointerMoveHandler = (event: ReactMouseEvent) => {
    if (tooltipState.getState().pinned || sliceId === 'slice-thinner-slices') {
      return;
    }

    const tooltipData = buildTooltipData(
      sliceId,
      data,
      handlerCatch,
      formatter,
    );

    hover(event, tooltipData);
  };

  const onMouseClickHandler = (event: ReactMouseEvent) => {
    event.stopPropagation();

    if (sliceId === 'slice-thinner-slices') {
      reset();
    } else {
      const tooltipData = buildTooltipData(
        sliceId,
        data,
        handlerCatch,
        formatter,
      );

      if (tooltipState.getState().pinned) {
        unpin();
        hover(event, tooltipData);
      } else {
        pin(event, tooltipData);
      }
    }
  };

  return {
    onPointerMoveHandler,
    onMouseClickHandler,
  };
}
